// BuildChunkClusters queries chunk IDs for the namespace, checks a fingerprint
// cache, computes pairwise co-occurrence between chunks via shared entities,
// calls ClusterEntities, persists results, and returns a map[chunkID]clusterID.
func BuildChunkClusters(
	conn DBConn,
	namespace string,
	algorithm string,
	minChunks int,
	force bool,
) (map[string]int, error) {
	rows, err := conn.Execute(
		"SELECT DISTINCT chunk_id FROM chunk_entities WHERE COALESCE(namespace, 'global') = ?",
		[]interface{}{namespace},
	)
	if err != nil {
		return nil, fmt.Errorf("build_chunk_clusters: query chunk_ids: %w", err)
	}
	var chunkIDs []string
	for _, r := range rows {
		chunkIDs = append(chunkIDs, r[0].(string))
	}

	if len(chunkIDs) < minChunks {
		return map[string]int{}, nil
	}

	fingerprint := chunkFingerprint(chunkIDs)

	if !force {
		cacheRow, err := conn.FetchOne(
			"SELECT chunk_fingerprint FROM context_graph_cache WHERE COALESCE(namespace, 'global') = ?",
			[]interface{}{namespace},
		)
		if err == nil && cacheRow != nil && cacheRow[0].(string) == fingerprint {
			existing, err := conn.Execute(
				"SELECT chunk_id, cluster_id FROM chunk_clusters WHERE COALESCE(namespace, 'global') = ?",
				[]interface{}{namespace},
			)
			if err == nil && len(existing) > 0 {
				cached := make(map[string]int, len(existing))
				for _, r := range existing {
					cached[r[0].(string)] = int(r[1].(int64))
				}
				return cached, nil
			}
		}
	}

	ceRows, err := conn.Execute(
		"SELECT chunk_id, entity_id FROM chunk_entities WHERE COALESCE(namespace, 'global') = ?",
		[]interface{}{namespace},
	)
	if err != nil {
		return nil, fmt.Errorf("build_chunk_clusters: query chunk_entities: %w", err)
	}
	chunkToEntities := make(map[string][]string)
	for _, row := range ceRows {
		cid := row[0].(string)
		eid := row[1].(string)
		chunkToEntities[cid] = append(chunkToEntities[cid], eid)
	}

	entityToChunks := make(map[string][]string)
	for chunkID, entityIDs := range chunkToEntities {
		for _, eid := range entityIDs {
			entityToChunks[eid] = append(entityToChunks[eid], chunkID)
		}
	}

	type pairKey struct{ a, b string }
	cooccurrence := make(map[pairKey]float64)
	for _, chunks := range entityToChunks {
		for i := 0; i < len(chunks); i++ {
			for j := i + 1; j < len(chunks); j++ {
				a, b := chunks[i], chunks[j]
				if a > b {
					a, b = b, a
				}
				cooccurrence[pairKey{a, b}] += 1.0
			}
		}
	}

	// Flatten cooccurrence to map[string]float64 keyed "a|b" for ClusterEntities
	coocFlat := make(map[string]float64, len(cooccurrence))
	for k, v := range cooccurrence {
		coocFlat[k.a+"|"+k.b] = v
	}

	clusterMap, err := ClusterEntities(coocFlat, chunkIDs, algorithm)
	if err != nil {
		return nil, fmt.Errorf("build_chunk_clusters: cluster_entities: %w", err)
	}

	result := make(map[string]int, len(clusterMap))
	for chunkID, label := range clusterMap {
		numStr := strings.TrimPrefix(label, "cluster_")
		n, err := strconv.Atoi(numStr)
		if err != nil {
			return nil, fmt.Errorf("build_chunk_clusters: bad label %q: %w", label, err)
		}
		result[chunkID] = n
	}

	if _, err := conn.Execute("DELETE FROM chunk_clusters WHERE namespace = ?", []interface{}{namespace}); err != nil {
		return nil, fmt.Errorf("build_chunk_clusters: delete: %w", err)
	}
	if len(result) > 0 {
		var insertRows [][]interface{}
		for cid, cidInt := range result {
			insertRows = append(insertRows, []interface{}{cid, cidInt, namespace})
		}
		if err := conn.ExecuteMany(
			"INSERT INTO chunk_clusters (chunk_id, cluster_id, namespace) VALUES (?, ?, ?)",
			insertRows,
		); err != nil {
			return nil, fmt.Errorf("build_chunk_clusters: insert: %w", err)
		}
	}
	return result, nil
}

