// parse strips markdown fences from raw, JSON-decodes it as an array of objects,
// validates each entry's verb against the extractor's verb set, and returns
// a slice of SVOTriples. Returns nil, nil when the JSON is invalid or not an array.
func (e *SVOExtractor) parse(raw string, chunkID *string) ([]SVOTriple, error) {
	// Strip ```json ... ``` or ``` ... ``` fences
	cleaned := markdownFenceRE.ReplaceAllString(raw, "")
	cleaned = strings.TrimSpace(cleaned)

	var decoded []interface{}
	if err := json.Unmarshal([]byte(cleaned), &decoded); err != nil {
		// Signal parse failure with nil slice and no error — caller retries
		return nil, nil
	}
	if len(decoded) == 0 {
		// Empty array is valid — return empty slice
		return []SVOTriple{}, nil
	}

	var triples []SVOTriple
	for _, item := range decoded {
		row, ok := item.(map[string]interface{})
		if !ok {
			continue
		}
		verbRaw, ok := row["verb"]
		if !ok {
			continue
		}
		verb, ok := verbRaw.(string)
		if !ok {
			continue
		}
		if _, allowed := e.verbSet[verb]; !allowed {
			continue
		}
		subjRaw, hasSubj := row["subject_id"]
		objRaw, hasObj := row["object_id"]
		confRaw, hasConf := row["confidence"]
		if !hasSubj || !hasObj || !hasConf {
			continue
		}
		subj, ok1 := subjRaw.(string)
		obj, ok2 := objRaw.(string)
		conf, ok3 := confRaw.(float64)
		if !ok1 || !ok2 || !ok3 {
			continue
		}
		triples = append(triples, SVOTriple{
			SubjectID:     subj,
			Verb:          verb,
			ObjectID:      obj,
			Confidence:    conf,
			SourceChunkID: chunkID,
		})
	}
	return triples, nil
}
